-- ================================================================
-- Banque multilingue de citations originales pour radioamateurs
-- SQL PostgreSQL prêt à exécuter dans pgAdmin
-- Nombre de citations : 3532
-- Colonnes : citation_fr, citation_en, citation_de, citation_nl
-- Note : traductions automatiques de travail, prévues pour être relues avant publication officielle.
-- Généré le : 2026-04-26T20:40:32
-- ================================================================

SET client_encoding = 'UTF8';

BEGIN;

CREATE TABLE IF NOT EXISTS public.radioamateur_citations (
    id BIGSERIAL PRIMARY KEY,
    citation_fr TEXT NOT NULL,
    citation_en TEXT,
    citation_de TEXT,
    citation_nl TEXT,
    theme VARCHAR(120) NOT NULL,
    usage_context VARCHAR(80) NOT NULL DEFAULT 'site_web',
    source_type VARCHAR(80) NOT NULL DEFAULT 'originale',
    is_original BOOLEAN NOT NULL DEFAULT TRUE,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    display_order INTEGER,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Migration douce depuis l'ancienne version où la colonne française s'appelait citation.
DO $$
BEGIN
    IF EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = 'public'
          AND table_name = 'radioamateur_citations'
          AND column_name = 'citation'
    ) AND NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = 'public'
          AND table_name = 'radioamateur_citations'
          AND column_name = 'citation_fr'
    ) THEN
        ALTER TABLE public.radioamateur_citations RENAME COLUMN citation TO citation_fr;
    END IF;
END
$$;

ALTER TABLE public.radioamateur_citations ADD COLUMN IF NOT EXISTS citation_fr TEXT;
ALTER TABLE public.radioamateur_citations ADD COLUMN IF NOT EXISTS citation_en TEXT;
ALTER TABLE public.radioamateur_citations ADD COLUMN IF NOT EXISTS citation_de TEXT;
ALTER TABLE public.radioamateur_citations ADD COLUMN IF NOT EXISTS citation_nl TEXT;

ALTER TABLE public.radioamateur_citations
    DROP CONSTRAINT IF EXISTS uq_radioamateur_citations_language_citation;

CREATE UNIQUE INDEX IF NOT EXISTS ux_radioamateur_citations_citation_fr
    ON public.radioamateur_citations (citation_fr);

COMMENT ON TABLE public.radioamateur_citations IS 'Banque multilingue de citations originales pour site, club, formation ou communication radioamateur.';
COMMENT ON COLUMN public.radioamateur_citations.citation_fr IS 'Texte original français de la citation.';
COMMENT ON COLUMN public.radioamateur_citations.citation_en IS 'Traduction anglaise de la citation.';
COMMENT ON COLUMN public.radioamateur_citations.citation_de IS 'Traduction allemande de la citation.';
COMMENT ON COLUMN public.radioamateur_citations.citation_nl IS 'Traduction néerlandaise de la citation.';
COMMENT ON COLUMN public.radioamateur_citations.theme IS 'Thème éditorial de la citation.';
COMMENT ON COLUMN public.radioamateur_citations.usage_context IS 'Usage conseillé : accueil, hero, club, formation, technique, etc.';
COMMENT ON COLUMN public.radioamateur_citations.source_type IS 'Origine ou nature de la citation.';

CREATE INDEX IF NOT EXISTS ix_radioamateur_citations_theme
    ON public.radioamateur_citations (theme);
CREATE INDEX IF NOT EXISTS ix_radioamateur_citations_usage_context
    ON public.radioamateur_citations (usage_context);
CREATE INDEX IF NOT EXISTS ix_radioamateur_citations_active
    ON public.radioamateur_citations (is_active);

CREATE OR REPLACE FUNCTION public.set_radioamateur_citations_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS tr_radioamateur_citations_updated_at
    ON public.radioamateur_citations;
CREATE TRIGGER tr_radioamateur_citations_updated_at
BEFORE UPDATE ON public.radioamateur_citations
FOR EACH ROW
EXECUTE FUNCTION public.set_radioamateur_citations_updated_at();

ON CONFLICT (citation_fr) DO UPDATE SET
    citation_en = EXCLUDED.citation_en,
    citation_de = EXCLUDED.citation_de,
    citation_nl = EXCLUDED.citation_nl,
    theme = EXCLUDED.theme,
    usage_context = EXCLUDED.usage_context,
    source_type = EXCLUDED.source_type,
    is_original = EXCLUDED.is_original,
    is_active = EXCLUDED.is_active,
    display_order = EXCLUDED.display_order,
    updated_at = NOW();

COMMIT;
